            if isinstance(current_program, str) and current_program.strip():
                current_program = self._pretty_json(current_program)
            if isinstance(parent_program, str) and parent_program.strip():
                parent_program = self._pretty_json(parent_program)
            else:
                parent_program = ""
        # Pick user template
        if template_key:
